const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 90);
const items = $input.all().map(i => i.json).filter(i => !i.date || new Date(i.date) >= cutoff);
// Aggregate themes and problems
const themeCount = {};
const problemList = [];
for (const item of items) {
  const themes = Array.isArray(item.themes) ? item.themes : (item.themes||'').split(',').map(t=>t.trim());
  for (const t of themes) { if (t) themeCount[t] = (themeCount[t]||0) + 1; }
  if (Array.isArray(item.problems_mentioned)) problemList.push(...item.problems_mentioned);
}
const topThemes = Object.entries(themeCount).sort((a,b)=>b[1]-a[1]).slice(0,20).map(([t,c])=>({theme:t,count:c}));
return [{ json: { total_items: items.length, period_days: 90, top_themes: topThemes, problems: problemList.slice(0,100), raw_sample: items.slice(0,30) } }];

let ai;
try { ai = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); }
catch { ai = { opportunities:[] }; }
const sorted = (ai.opportunities||[]).sort((a,b) => (b.confidence||0)-(a.confidence||0));
return [{ json: { generated_at: new Date().toISOString(), total_items_analyzed: $('Aggregate Evidence').first().json.total_items, period_days: 90, opportunities: sorted, research_gaps: ai.research_gaps||[], period_summary: ai.period_summary||'' } }];
